import { KeyboardControls, type KeyboardControlsEntry } from '@react-three/drei'
import { Canvas } from '@react-three/fiber'
import { Physics } from '@react-three/rapier'
import type { ReactNode } from 'react'
import { WorldContext } from './context'
import { keyboardMap as defaultKeyboardMap } from './keyboard'
import type { Vec3 } from './types'

export interface WorldProps {
  unit?: number
  gravity?: Vec3
  keyboardMap?: KeyboardControlsEntry[]
  /** Render the default light rig. Set false to supply your own (e.g. <LightRig>). */
  lights?: boolean
  /** Fired when a pointer click misses every object (used to deselect in the editor). */
  onPointerMissed?: () => void
  debug?: boolean
  children?: ReactNode
}

export function World({
  unit = 1,
  gravity = [0, -9.81, 0],
  keyboardMap = defaultKeyboardMap,
  lights = true,
  onPointerMissed,
  debug = false,
  children,
}: WorldProps) {
  return (
    <KeyboardControls map={keyboardMap}>
      <Canvas shadows camera={{ position: [6, 4, 6], fov: 60 }} onPointerMissed={onPointerMissed}>
        <WorldContext.Provider value={{ unit, gravity }}>
          {lights && (
            <>
              <ambientLight intensity={0.6} />
              <directionalLight
                position={[12, 18, 8]}
                intensity={1.6}
                castShadow
                shadow-mapSize={[2048, 2048]}
                shadow-camera-near={1}
                shadow-camera-far={60}
                shadow-camera-left={-25}
                shadow-camera-right={25}
                shadow-camera-top={25}
                shadow-camera-bottom={-25}
              />
            </>
          )}
          <Physics gravity={gravity} debug={debug}>
            {children}
          </Physics>
        </WorldContext.Provider>
      </Canvas>
    </KeyboardControls>
  )
}

import { OrbitControls, TransformControls } from '@react-three/drei'
import { Leva, useControls } from 'leva'
import { type CSSProperties, useEffect, useState } from 'react'
import type { Object3D } from 'three'
import type { Vec3 } from './types'
import { World, type WorldProps } from './World'
import {
  type ComponentRegistry,
  type JsonValue,
  serializeWorld,
  type WorldData,
  type WorldNode,
} from './world-data'

type TransformMode = 'translate' | 'rotate'
type Selection = { index: number; object: Object3D } | null

export interface WorldEditorProps extends Omit<WorldProps, 'children' | 'unit' | 'gravity'> {
  data: WorldData
  registry: ComponentRegistry
  onChange: (next: WorldData) => void
}

/** Nodes rendered without a transform (no meaningful position to gizmo). */
const NON_SELECTABLE = new Set(['Sky', 'LightRig'])
/** Nodes skipped in the editor (no FPS controller while orbiting). */
const SKIPPED = new Set(['Player'])

const asVec3 = (value: JsonValue | undefined): Vec3 | undefined =>
  Array.isArray(value) && value.length === 3 ? (value as unknown as Vec3) : undefined

/** Edit a world data-first: orbit camera, click-select, gizmo move/rotate, leva props — all writing back to `WorldData`. */
export function WorldEditor({ data, registry, onChange, ...worldProps }: WorldEditorProps) {
  const [selected, setSelected] = useState<Selection>(null)
  const [mode, setMode] = useState<TransformMode>('translate')

  useEffect(() => {
    const onKey = (event: KeyboardEvent) => {
      if (event.key === 'Escape') setSelected(null)
      else if (event.key === 'g') setMode('translate')
      else if (event.key === 'r') setMode('rotate')
    }
    window.addEventListener('keydown', onKey)
    return () => window.removeEventListener('keydown', onKey)
  }, [])

  const patchNode = (index: number, patch: Record<string, JsonValue>) => {
    const nodes = data.nodes.map((node, i) =>
      i === index ? { ...node, props: { ...node.props, ...patch } } : node,
    )
    onChange({ ...data, nodes })
  }

  const commitTransform = () => {
    if (!selected) return
    const { position, rotation } = selected.object
    const r = (n: number) => Math.round(n * 1000) / 1000
    patchNode(selected.index, {
      position: [r(position.x), r(position.y), r(position.z)],
      rotation: [r(rotation.x), r(rotation.y), r(rotation.z)],
    })
  }

  return (
    <>
      <World
        {...worldProps}
        unit={data.unit}
        gravity={data.gravity}
        onPointerMissed={() => setSelected(null)}
      >
        <OrbitControls makeDefault />
        <EditableNodes
          nodes={data.nodes}
          registry={registry}
          onSelect={(index, object) => setSelected({ index, object })}
        />
        {selected && (
          <TransformControls object={selected.object} mode={mode} onMouseUp={commitTransform} />
        )}
      </World>

      <Leva hidden={selected === null} />
      <EditorToolbar mode={mode} onMode={setMode} data={data} selected={selected?.index ?? null} />
      {selected !== null && (
        <NodeControls
          index={selected.index}
          node={data.nodes[selected.index]}
          onPatch={patchNode}
        />
      )}
    </>
  )
}

interface EditableNodesProps {
  nodes: WorldNode[]
  registry: ComponentRegistry
  onSelect: (index: number, object: Object3D) => void
}

function EditableNodes({ nodes, registry, onSelect }: EditableNodesProps) {
  return (
    <>
      {nodes.map((node, index) => {
        if (SKIPPED.has(node.type)) return null
        const Component = registry[node.type]
        if (!Component) return null

        if (NON_SELECTABLE.has(node.type)) {
          return <Component key={index} {...node.props} />
        }

        const { position, rotation, ...rest } = node.props ?? {}
        return (
          // biome-ignore lint/a11y/noStaticElementInteractions: <group> is a three.js object, not a DOM element
          <group
            key={index}
            position={asVec3(position) ?? [0, 0, 0]}
            rotation={asVec3(rotation) ?? [0, 0, 0]}
            onClick={(event) => {
              event.stopPropagation()
              onSelect(index, event.eventObject)
            }}
          >
            <Component {...rest} />
          </group>
        )
      })}
    </>
  )
}

interface NodeControlsProps {
  index: number
  node: WorldNode
  onPatch: (index: number, patch: Record<string, JsonValue>) => void
}

function NodeControls({ index, node, onPatch }: NodeControlsProps) {
  const props = node.props ?? {}
  const position = asVec3(props.position) ?? [0, 0, 0]
  const rotation = asVec3(props.rotation) ?? [0, 0, 0]
  const seed = typeof props.seed === 'number' ? props.seed : undefined

  useControls(
    `${node.type} #${index}`,
    () => ({
      position: {
        value: { x: position[0], y: position[1], z: position[2] },
        step: 0.1,
        onChange: (
          v: { x: number; y: number; z: number },
          _path: string,
          ctx: { initial: boolean },
        ) => {
          if (!ctx.initial) onPatch(index, { position: [v.x, v.y, v.z] })
        },
      },
      rotation: {
        value: { x: rotation[0], y: rotation[1], z: rotation[2] },
        step: 0.05,
        onChange: (
          v: { x: number; y: number; z: number },
          _path: string,
          ctx: { initial: boolean },
        ) => {
          if (!ctx.initial) onPatch(index, { rotation: [v.x, v.y, v.z] })
        },
      },
      ...(seed !== undefined
        ? {
            seed: {
              value: seed,
              step: 1,
              onChange: (v: number, _path: string, ctx: { initial: boolean }) => {
                if (!ctx.initial) onPatch(index, { seed: Math.round(v) })
              },
            },
          }
        : {}),
    }),
    [index],
  )

  return null
}

const TOOLBAR: CSSProperties = {
  position: 'fixed',
  top: '1rem',
  left: '1rem',
  display: 'flex',
  gap: '0.5rem',
  alignItems: 'center',
  zIndex: 10,
  fontFamily: 'system-ui, sans-serif',
}

const button = (active: boolean): CSSProperties => ({
  padding: '0.4rem 0.7rem',
  borderRadius: 6,
  border: 'none',
  cursor: 'pointer',
  background: active ? '#4a90d9' : 'rgba(0, 0, 0, 0.6)',
  color: '#fff',
  fontSize: '0.8rem',
})

interface EditorToolbarProps {
  mode: TransformMode
  onMode: (mode: TransformMode) => void
  data: WorldData
  selected: number | null
}

function EditorToolbar({ mode, onMode, data, selected }: EditorToolbarProps) {
  const exportWorld = async () => {
    const text = serializeWorld(data)
    try {
      await navigator.clipboard.writeText(text)
    } catch {
      // clipboard may be unavailable; the log below is the fallback
    }
    console.log(text)
  }

  return (
    <div style={TOOLBAR}>
      <button
        type="button"
        style={button(mode === 'translate')}
        onClick={() => onMode('translate')}
      >
        Move
      </button>
      <button type="button" style={button(mode === 'rotate')} onClick={() => onMode('rotate')}>
        Rotate
      </button>
      <button type="button" style={button(false)} onClick={exportWorld}>
        Export JSON
      </button>
      <span style={{ color: 'rgba(255,255,255,0.75)', fontSize: '0.8rem' }}>
        {selected === null ? 'click a component · Esc to deselect' : `selected #${selected}`}
      </span>
    </div>
  )
}

import type { ComponentRegistry, WorldNode } from './world-data'

export interface WorldNodesProps {
  nodes: WorldNode[]
  registry: ComponentRegistry
}

/** Render a list of world nodes by looking each `type` up in the registry. Recurses into children. */
export function WorldNodes({ nodes, registry }: WorldNodesProps) {
  return (
    <>
      {nodes.map((node, index) => {
        const Component = registry[node.type]
        if (!Component) {
          console.warn(`[runek] Unknown component "${node.type}" — skipped.`)
          return null
        }
        const children = node.children?.length ? (
          <WorldNodes nodes={node.children} registry={registry} />
        ) : null
        return (
          <Component key={index} {...node.props}>
            {children}
          </Component>
        )
      })}
    </>
  )
}

import { World, type WorldProps } from './World'
import { WorldNodes } from './WorldNodes'
import type { ComponentRegistry, WorldData } from './world-data'

export interface WorldRendererProps extends Omit<WorldProps, 'children' | 'unit' | 'gravity'> {
  data: WorldData
  registry: ComponentRegistry
}

/** Render a `WorldData` object inside a `<World>`, resolving each node via the registry. */
export function WorldRenderer({ data, registry, ...worldProps }: WorldRendererProps) {
  return (
    <World unit={data.unit} gravity={data.gravity} {...worldProps}>
      <WorldNodes nodes={data.nodes} registry={registry} />
    </World>
  )
}

import { createContext } from 'react'
import type { WorldContextValue } from './types'

export const WorldContext = createContext<WorldContextValue>({
  unit: 1,
  gravity: [0, -9.81, 0],
})

export type Rng = () => number

/** Deterministic seeded RNG: a given seed always yields the same sequence in [0, 1). */
export function rng(seed: number): Rng {
  let s = seed >>> 0
  return () => {
    s = Math.imul(s ^ (s >>> 15), 1 | s)
    s ^= s + Math.imul(s ^ (s >>> 7), 61 | s)
    return ((s ^ (s >>> 14)) >>> 0) / 4294967296
  }
}

export const range = (r: Rng, min: number, max: number) => min + r() * (max - min)

export const int = (r: Rng, min: number, max: number) => Math.floor(range(r, min, max + 1))

export const pick = <T>(r: Rng, items: readonly T[]): T => items[Math.floor(r() * items.length)]

/** Derive a stable child seed, so nested components stay deterministic. */
export const sub = (seed: number, n: number) => (Math.imul(seed >>> 0, 0x9e3779b1) + n) >>> 0

export type Vec3 = [number, number, number]

/** The contract every Runek component implements. */
export interface WorldComponentProps {
  position?: Vec3
  rotation?: Vec3
  seed?: number
}

export interface WorldContextValue {
  /** Meters per unit. Components scale their geometry by this. */
  unit: number
  gravity: Vec3
}

import { useContext } from 'react'
import { WorldContext } from './context'

export const useWorld = () => useContext(WorldContext)

import type { ComponentType } from 'react'
import type { Vec3 } from './types'

export type JsonValue =
  | string
  | number
  | boolean
  | null
  | JsonValue[]
  | { [key: string]: JsonValue }

/** One placed component: a registry key, its props, and optional nested children. */
export interface WorldNode {
  /** Registry key — the component's name, e.g. "Bookshelf". */
  type: string
  props?: Record<string, JsonValue>
  children?: WorldNode[]
}

/** A whole world as plain data — diffable, forkable, version-controlled like any file. */
export interface WorldData {
  version: 1
  unit?: number
  gravity?: Vec3
  nodes: WorldNode[]
}

// biome-ignore lint/suspicious/noExplicitAny: a registry holds components with heterogeneous prop types
export type ComponentRegistry = Record<string, ComponentType<any>>

/** Serialize a world to pretty JSON text. */
export function serializeWorld(data: WorldData): string {
  return `${JSON.stringify(data, null, 2)}\n`
}

/** Parse and lightly validate world JSON text. Throws on an unsupported shape. */
export function parseWorld(json: string): WorldData {
  const data = JSON.parse(json) as WorldData
  if (data.version !== 1) {
    throw new Error(
      `Unsupported world version: ${JSON.stringify((data as { version?: unknown }).version)}`,
    )
  }
  if (!Array.isArray(data.nodes)) {
    throw new Error('World data must have a "nodes" array')
  }
  return data
}
